{
  "user": {
    "plan": "max5x",
    "comment": "Options: pro, max5x, max20x - Set this to your Claude subscription plan"
  },
  "ccusage_version": "17.1.0",
  "limits": {
    "weekly": {
      "pro": 300,
      "max5x": 500,
      "max20x": 850,
      "comment": "Adjust if Anthropic changes published limits."
    },
    "context": 200,
    "cost": 20,
    "token": 220000,
    "comment": "Context limit (in thousands), cost limit per 5-hour session, token limit for tracking"
  },
  "paths": {
    "claude_projects": "~/.claude/projects/",
    "comment": "Path to your Claude Code projects directory"
  },
  "display": {
    "bar_length": 10,
    "transcript_tail_lines": 200,
    "session_activity_threshold_minutes": 5,
    "show_labels": true,
    "comment": "Display settings: progress bar length, lines to read from transcript, minutes for active session detection, show_labels (true=show 'daily', 'total', etc.; false=hide labels for concise display)"
  },
  "colors": {
    "orange": "\\033[1;93m",
    "bright_orange": "\\033[38;5;208m",
    "dim_orange": "\\033[2;38;5;208m",
    "red": "\\033[31m",
    "dim_red": "\\033[2;31m",
    "pink": "\\033[38;5;225m",
    "dim_pink": "\\033[2;38;5;225m",
    "bright_pink": "\\033[1;38;5;225m",
    "green": "\\033[38;5;194m",
    "dim_green": "\\033[2;38;5;194m",
    "purple": "\\033[35m",
    "cyan": "\\033[96m",
    "dim_blue": "\\033[94m",
    "reset": "\\033[0m",
    "comment": "ANSI color codes for statusline elements. Use '2;' prefix for dim, '1;' for bright. Available: orange, bright_orange, dim_orange, red, dim_red, pink, dim_pink, bright_pink, green, dim_green, purple, cyan, dim_blue."
  },
  "multi_layer": {
    "layer1": {
      "threshold_multiplier": 0.3,
      "color": "green",
      "comment": "Layer 1: 0-0.3x of cost_limit (base threshold). Thresholds calculated as: cost_limit × multiplier."
    },
    "layer2": {
      "threshold_multiplier": 0.5,
      "color": "orange",
      "comment": "Layer 2: 0.3x-0.5x of cost_limit. Visual scale auto-calculated for each layer."
    },
    "layer3": {
      "threshold_multiplier": 1.0,
      "color": "red",
      "comment": "Layer 3: 0.5x-1.0x of cost_limit. Multipliers define threshold relative to base limit."
    },
    "comment": "5-hour window layers. Base threshold = cost_limit. Layer thresholds = base × threshold_multiplier. Visual scaling auto-calculated per layer."
  },
  "daily_layer": {
    "layer1": {
      "threshold_multiplier": 1.0,
      "color": "dim_green",
      "comment": "Layer 1: 0-1.0x of base (weekly_limit/7 or recommend value). Base changes dynamically with mode. Uses dimmed color for less distraction."
    },
    "layer2": {
      "threshold_multiplier": 1.5,
      "color": "dim_orange",
      "comment": "Layer 2: 1.0x-1.5x of base. Base is weekly_limit/7 (static) or recommend value (dynamic mode). Uses dimmed color for less distraction."
    },
    "comment": "Daily usage layers. Base threshold = weekly_limit/7 (static mode) or recommend value (dynamic mode when weekly recommend enabled). Layer thresholds = base × threshold_multiplier. Visual scaling auto-calculated per layer. Uses dimmed colors to reduce visual distraction."
  },
  "context_layer": {
    "layer1": {
      "threshold_multiplier": 1.0,
      "color": "purple",
      "comment": "Layer 1: 0-1.0x of context_limit. Normal usage range."
    },
    "layer2": {
      "threshold_multiplier": 2.0,
      "color": "orange",
      "comment": "Layer 2: 1.0x-2.0x of context_limit. Elevated usage."
    },
    "layer3": {
      "threshold_multiplier": 3.0,
      "color": "red",
      "comment": "Layer 3: 2.0x-3.0x of context_limit. High usage."
    },
    "comment": "Context window layers. Base threshold = context_limit. Layer thresholds = base × threshold_multiplier. Allows tracking beyond nominal limit. Visual scaling auto-calculated per layer."
  },
  "sections": {
    "show_directory": true,
    "show_context": true,
    "show_five_hour_window": true,
    "show_daily": true,
    "show_weekly": true,
    "show_monthly": true,
    "show_timer": true,
    "show_token_rate": true,
    "show_sessions": true,
    "weekly_display_mode": "recommend",
    "comment": "Toggle visibility of statusline sections - set to false to hide any section. show_directory: project name (default on, bold bright orange). show_five_hour_window: 5-hour cost window ($X/$Y [bar] %). show_daily: daily cycle tracker. show_weekly: weekly percentage. show_monthly: monthly total cost. show_timer: reset countdown. show_token_rate: current token burn rate (tokens/min). show_sessions: active session count. weekly_display_mode: 'usage' (shows weekly usage %), 'avail' (shows available % left with label 'avail'), 'recommend' (shows recommended daily usage % to finish allocated budget with label 'recom')."
  },
  "tracking": {
    "weekly_scheme": "ccusage",
    "official_reset_date": "",
    "payment_cycle_start_date": "2025-05-01T00:00:00+00:00",
    "weekly_baseline_percent": 0,
    "cache_duration_seconds": 300,
    "comment": "Weekly tracking: 'ccusage' (default, uses ISO weeks) or 'ccusage_r' (optional, matches Anthropic console schedule). To use ccusage_r: set official_reset_date from your console's 'Resets [date/time]' (format: 2025-10-08T15:00:00-07:00 for 'Oct 8, 3pm Vancouver'). payment_cycle_start_date: optional, set to track monthly cost from your billing cycle start (format: 2025-10-01T15:00:00-07:00 - date is cycle start, time is copied from official_reset_date for consistency). weekly_baseline_percent compensates for untracked costs from deleted transcripts (clear/compact commands) - set to the percentage gap between your Anthropic console and statusline (e.g., console 15% vs statusline 10% → set to 5). cache_duration_seconds controls how long ccusage_r results are cached (default: 300 = 5 minutes). See README for setup guide."
  }
}

